inline const FSP *GetFSP(const void *buf) {
  return ::flatbuffers::GetRoot<FSP>(buf);
}

inline const FSP *GetSizePrefixedFSP(const void *buf) {
  return ::flatbuffers::GetSizePrefixedRoot<FSP>(buf);
}

inline const char *FSPIdentifier() {
  return "$FSP";
}

inline bool FSPBufferHasIdentifier(const void *buf) {
  return ::flatbuffers::BufferHasIdentifier(
      buf, FSPIdentifier());
}

inline bool SizePrefixedFSPBufferHasIdentifier(const void *buf) {
  return ::flatbuffers::BufferHasIdentifier(
      buf, FSPIdentifier(), true);
}

template <bool B = false>
inline bool VerifyFSPBuffer(
    ::flatbuffers::VerifierTemplate<B> &verifier) {
  return verifier.template VerifyBuffer<FSP>(FSPIdentifier());
}

template <bool B = false>
inline bool VerifySizePrefixedFSPBuffer(
    ::flatbuffers::VerifierTemplate<B> &verifier) {
  return verifier.template VerifySizePrefixedBuffer<FSP>(FSPIdentifier());
}

inline void FinishFSPBuffer(
    ::flatbuffers::FlatBufferBuilder &fbb,
    ::flatbuffers::Offset<FSP> root) {
  fbb.Finish(root, FSPIdentifier());
}

inline void FinishSizePrefixedFSPBuffer(
    ::flatbuffers::FlatBufferBuilder &fbb,
    ::flatbuffers::Offset<FSP> root) {
  fbb.FinishSizePrefixed(root, FSPIdentifier());
}

